import { OperationNodeTransformer } from '../../operation-node/operation-node-transformer.js'
import type { OverNode } from '../../operation-node/over-node.js'
import { freeze } from '../../util/object-utils.js'
import type { QueryId } from '../../util/query-id.js'

export class SimplifyFrameTransformer extends OperationNodeTransformer {
  protected override transformOver(node: OverNode, queryId: QueryId): OverNode {
    const transformed = super.transformOver(node, queryId)

    if (
      transformed.frame &&
      isRedundantFrame(transformed.frame, !!transformed.orderBy)
    ) {
      const { frame, ...rest } = transformed
      return freeze(rest)
    }

    return transformed
  }
}

function isRedundantFrame(frame: FrameNode, hasOrderBy: boolean): boolean {
  if (frame.unit !== 'range' || frame.exclusion) {
    return false
  }

  if (frame.start.offset || frame.end?.offset) {
    return false
  }

  if (frame.start.type !== 'unbounded preceding') {
    return false
  }

  const effectiveEndType = frame.end ? frame.end.type : 'current row'
  const expectedEndType = hasOrderBy ? 'current row' : 'unbounded following'

  return effectiveEndType === expectedEndType
}
