import type { RootOperationNode } from '../../query-compiler/query-compiler.js'
import type { UnknownRow } from '../../util/type-utils.js'
import type {
  KyselyPlugin,
  PluginTransformQueryArgs,
  PluginTransformResultArgs,
} from '../kysely-plugin.js'
import { SimplifyFrameTransformer } from './simplify-frame-transformer.js'

/**
 * Plugin that strips `over` clause frame extents that only restate the
 * SQL-standard implicit default, shortening the compiled SQL without
 * changing its meaning.
 *
 * - `over(order by ...)` implicitly applies `range between unbounded
 *   preceding and current row`.
 * - `over()` (no `order by`) implicitly applies `range between unbounded
 *   preceding and unbounded following`.
 *
 * Any frame that uses `rows` or `groups` mode, carries an exclusion
 * clause, or uses non-default bound types or expression-based offsets is
 * left untouched.
 */
export class SimplifyFramePlugin implements KyselyPlugin {
  readonly #transformer = new SimplifyFrameTransformer()

  transformQuery(args: PluginTransformQueryArgs): RootOperationNode {
    return this.#transformer.transformNode(args.node, args.queryId)
  }

  transformResult(
    args: PluginTransformResultArgs,
  ): Promise<QueryResult<UnknownRow>> {
    return Promise.resolve(args.result)
  }
}
